from __future__ import annotations

import argparse
import hashlib
import json
import ntpath
import re
import sys
from collections import Counter, deque
from pathlib import Path, PureWindowsPath
from typing import Any, Iterable

BRIDGE_SCHEMA = "foxai.agent_fox.technical_core.v1a2r2.immutable_static_bridge.v1"
CONTRACT_SCHEMA = "foxai.agent_fox.technical_core.v1a2r2.immutable_static_bridge_contract.v1"
DEFAULT_PROJECT_ROOT = Path(r"Z:\FOXAI")
DEFAULT_V1A2_DIR = Path(
    r"Z:\FOXAI\System\EngineeringWorkshop\missions\ENG-20260721-053749-E3BE2A_V1A2_STATIC_BRIDGE"
)
DEFAULT_OUTPUT_DIR = Path(
    r"Z:\FOXAI\System\EngineeringWorkshop\missions\ENG-20260721-063725-BFCAB9_V1A2R2_IMMUTABLE_BRIDGE"
)
DEFAULT_MISSION_ID = "ENG-20260721-063725-BFCAB9"

MAX_SOURCE_FILE_BYTES = 4 * 1024 * 1024
MAX_LAUNCHER_FILE_BYTES = 1024 * 1024
MAX_REFERENCE_LINES_PER_FILE = 5000
MAX_REFERENCE_SHARD_RECORDS = 1200
MAX_REFERENCE_SHARD_BYTES = 2 * 1024 * 1024
MAX_LINE_LENGTH = 480
MAX_QUERY_RESULTS = 100
MAX_TRACE_DEPTH = 12
MAX_OUTPUT_BYTES = 128 * 1024 * 1024

SHELL_BUILTINS = {
    "if", "else", "echo", "set", "where", "for", "goto", "rem", "copy", "xcopy",
    "robocopy", "move", "del", "erase", "rd", "rmdir", "md", "mkdir", "type", "title",
    "timeout", "pause", "exit", "shift", "setlocal", "endlocal", "verify", "path", "prompt",
    "assoc", "break", "call", "cd", "chdir", "cls", "color", "date", "dir", "doskey",
    "ftype", "keys", "mklink", "more", "popd", "pushd", "ren", "rename", "start", "time",
    "ver", "vol", "choice", "find", "findstr", "sort", "tree", "attrib", "fc", "comp",
}
FILE_OPERATION_WORDS = {"copy", "xcopy", "robocopy", "move", "del", "erase", "rd", "rmdir", "md", "mkdir", "ren", "rename"}
OS_SHELL_WORDS = {"cmd", "cmd.exe", "%comspec%", "powershell", "powershell.exe", "pwsh", "pwsh.exe"}
INTERPRETER_WORD_RE = re.compile(r"(?i)(?:^|\\|/)(?:python|pythonw|py)(?:\.exe)?$")
SCRIPT_SUFFIXES = {".py", ".pyw"}
LAUNCHER_SUFFIXES = {".bat", ".cmd", ".ps1"}
URL_RE = re.compile(r"(?i)\bhttps?://[^\s\"'<>]+")
PORT_RE = re.compile(r"(?i)(?:--port(?:=|\s+)|\bport\s*[:=]\s*|127\.0\.0\.1:|localhost:)(\d{2,5})")
ENV_REF_RE = re.compile(r"%(?:[A-Za-z_][A-Za-z0-9_]*)%")
DP0_RE = re.compile(r"(?i)%~dp0")
TOKEN_RE = re.compile(r""""(?:[^"\r\n]|"")*"|'[^'\r\n]*'|[^\s]+""")
BATCH_SET_RE = re.compile(r"""(?i)^\s*@?set\s+(?:"([^="]+)=([^"]*)"|([^=\s]+)=(.*))\s*$""")
BATCH_FOR_CANON_RE = re.compile(
    r"""(?i)^\s*@?for\s+%%([A-Za-z])\s+in\s+\(\s*"([^"]+)"\s*\)\s+do\s+set\s+"?([^=\s"]+)\s*=\s*%%~f\1"?\s*$"""
)
BATCH_LABEL_RE = re.compile(r"^\s*:([^:\s]+)\s*$")
BATCH_GOTO_RE = re.compile(r"(?i)^\s*@?goto\s+([^\s&|]+)")
BATCH_CD_RE = re.compile(r"(?i)^\s*@?(?:cd|chdir|pushd)\s+(?:/d\s+)?(.+?)\s*$")
BATCH_EXIST_RE = re.compile(r"(?i)^\s*@?if\s+(not\s+)?exist\s+(.+?)(?:\s+\(|\s+[^\s].*)?$", re.I)
SECRET_NAME_RE = re.compile(r"(?:api[_-]?key|secret|password|passwd|token|credential|private[_-]?key|client[_-]?secret)", re.I)
SECRET_LINE_RE = re.compile(
    r"(?i)(api[_-]?key|secret|password|passwd|token|credential|private[_-]?key|client[_-]?secret)"
    r"\s*[:=]\s*([^\s,;\]\}\)]+|[\"'][^\"']*[\"'])"
)


def pretty_bytes(value: Any) -> bytes:
    return (json.dumps(value, ensure_ascii=False, sort_keys=True, indent=2) + "\n").encode("utf-8")


def sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


_ACTIVE_CAPTURE: dict[str, dict[str, Any]] = {}
_REFERENCE_EXISTENCE_CACHE: dict[str, dict[str, Any]] = {}


def capture_key(path: Path | str) -> str:
    return str(path).replace("/", "\\").strip().casefold()


def set_active_capture(records: dict[str, dict[str, Any]]) -> None:
    global _ACTIVE_CAPTURE, _REFERENCE_EXISTENCE_CACHE
    _ACTIVE_CAPTURE = records
    _REFERENCE_EXISTENCE_CACHE = {}


def captured_record(path: Path | str) -> dict[str, Any] | None:
    return _ACTIVE_CAPTURE.get(capture_key(path))


def path_size(path: Path) -> int:
    record = captured_record(path)
    if record is not None and record.get("status") == "captured":
        return int(record["size_bytes"])
    return path.stat().st_size


def path_mtime_ns(path: Path) -> int:
    record = captured_record(path)
    if record is not None and record.get("status") == "captured":
        return int(record.get("modified_ns", 0))
    return path.stat().st_mtime_ns


def path_is_file(path: Path) -> bool:
    record = captured_record(path)
    if record is not None:
        return record.get("status") == "captured"
    return path.is_file()


def path_is_symlink(path: Path) -> bool:
    record = captured_record(path)
    if record is not None:
        return bool(record.get("is_symlink", False))
    return path.is_symlink()


def captured_bytes(path: Path) -> bytes | None:
    record = captured_record(path)
    if record is None or record.get("status") != "captured":
        return None
    return record.get("_bytes")


def reference_exists_once(path: Path | None) -> bool:
    if path is None:
        return False
    record = captured_record(path)
    if record is not None:
        return record.get("status") == "captured" and not record.get("is_symlink", False)
    key = capture_key(path)
    if key not in _REFERENCE_EXISTENCE_CACHE:
        try:
            exists = path.is_file() and not path.is_symlink()
            status = "existing_file" if exists else "not_existing_file"
        except (OSError, PermissionError) as exc:
            exists = False
            status = f"check_error:{type(exc).__name__}"
        _REFERENCE_EXISTENCE_CACHE[key] = {
            "path": norm_win(path),
            "exists": exists,
            "status": status,
            "checked_once": True,
        }
    return bool(_REFERENCE_EXISTENCE_CACHE[key]["exists"])


def capture_one(path: Path, *, roles: list[str], relative_path: str | None, max_bytes: int,
                expected_sha256: str | None = None, protected: bool = False,
                prerequisite: bool = False, payload: bool = False) -> dict[str, Any]:
    key = capture_key(path)
    existing = _ACTIVE_CAPTURE.get(key)
    if existing is not None:
        existing["roles"] = sorted(set(existing.get("roles", [])) | set(roles), key=str.casefold)
        existing["protected"] = bool(existing.get("protected") or protected)
        existing["prerequisite"] = bool(existing.get("prerequisite") or prerequisite)
        existing["payload"] = bool(existing.get("payload") or payload)
        if expected_sha256 and not existing.get("expected_sha256"):
            existing["expected_sha256"] = expected_sha256
        return existing
    base = {
        "path": norm_win(path),
        "_native_path": str(path),
        "relative_path": relative_path,
        "roles": sorted(set(roles), key=str.casefold),
        "protected": protected,
        "prerequisite": prerequisite,
        "payload": payload,
        "expected_sha256": expected_sha256,
        "capture_max_bytes": max_bytes,
        "is_symlink": False,
    }
    try:
        if not path.is_file():
            record = {**base, "status": "missing", "size_bytes": None, "modified_ns": None, "sha256": None, "_bytes": None}
        elif path.is_symlink():
            record = {**base, "status": "symlink_skipped", "is_symlink": True, "size_bytes": None, "modified_ns": None, "sha256": None, "_bytes": None}
        else:
            before = path.stat()
            if before.st_size > max_bytes:
                record = {**base, "status": "over_limit", "size_bytes": before.st_size, "modified_ns": before.st_mtime_ns, "sha256": None, "_bytes": None}
            else:
                raw = path.read_bytes()
                after = path.stat()
                record = {
                    **base,
                    "status": "captured",
                    "size_bytes": len(raw),
                    "modified_ns": after.st_mtime_ns,
                    "sha256": sha256_bytes(raw),
                    "changed_during_capture": before.st_size != after.st_size or before.st_mtime_ns != after.st_mtime_ns,
                    "_bytes": raw,
                }
    except (OSError, PermissionError) as exc:
        record = {**base, "status": "read_error", "error": f"{type(exc).__name__}:{exc}", "size_bytes": None, "modified_ns": None, "sha256": None, "_bytes": None}
    _ACTIVE_CAPTURE[key] = record
    return record


def public_capture_record(record: dict[str, Any]) -> dict[str, Any]:
    return {key: value for key, value in record.items() if key not in {"_bytes", "_native_path"}}


def mutable_state_path(path_text: str) -> bool:
    normalized = path_text.replace("/", "\\").casefold()
    name = PureWindowsPath(normalized).name
    suffix = PureWindowsPath(normalized).suffix
    if suffix in {".py", ".pyw", ".bat", ".cmd", ".ps1", ".js", ".html", ".css"}:
        return False
    segments = set(PureWindowsPath(normalized).parts)
    if segments & {"state", "states", "status", "statuses", "session", "sessions", "outbox", "runtime_state", "health_output"}:
        return True
    stems = ("active_profile", "runtime_state", "session_state", "health_status", "service_status", "current_status")
    return any(name.startswith(stem) for stem in stems) or name.endswith((".lock", ".tmp", ".journal", ".wal", ".log"))


def live_drift_report(records: dict[str, dict[str, Any]]) -> dict[str, Any]:
    rows: list[dict[str, Any]] = []
    counts = Counter()
    protected_changes: list[dict[str, Any]] = []
    for key in sorted(records):
        record = records[key]
        path = Path(record.get("_native_path") or record["path"])
        captured_status = record.get("status")
        captured_sha = record.get("sha256")
        captured_size = record.get("size_bytes")
        current_status = "missing"
        current_sha = None
        current_size = None
        try:
            if path.is_file() and not path.is_symlink():
                current_size = path.stat().st_size
                if current_size <= int(record.get("capture_max_bytes") or MAX_SOURCE_FILE_BYTES):
                    current_sha = hashlib.sha256(path.read_bytes()).hexdigest()
                    current_status = "captured_for_drift"
                else:
                    current_status = "over_limit"
            elif path.is_symlink():
                current_status = "symlink"
        except (OSError, PermissionError) as exc:
            current_status = f"read_error:{type(exc).__name__}"
        unchanged = (
            captured_status == "captured" and current_status == "captured_for_drift"
            and captured_sha == current_sha and captured_size == current_size
        ) or (
            captured_status in {"missing", "symlink_skipped", "over_limit"}
            and current_status == {"missing": "missing", "symlink_skipped": "symlink", "over_limit": "over_limit"}[captured_status]
        )
        if unchanged:
            classification = "unchanged"
        elif record.get("protected") or record.get("prerequisite") or record.get("payload"):
            classification = "protected_file_changed"
        elif mutable_state_path(record["path"]):
            classification = "mutable_state_changed"
        else:
            classification = "ordinary_source_changed"
        row = {
            "path": record["path"],
            "relative_path": record.get("relative_path"),
            "roles": record.get("roles", []),
            "classification": classification,
            "captured_status": captured_status,
            "captured_size_bytes": captured_size,
            "captured_sha256": captured_sha,
            "current_status": current_status,
            "current_size_bytes": current_size,
            "current_sha256": current_sha,
        }
        rows.append(row)
        counts[classification] += 1
        if classification == "protected_file_changed":
            protected_changes.append(row)
    return {
        "schema": BRIDGE_SCHEMA,
        "drift_check_kind": "bounded_hash_only_after_immutable_build",
        "records": rows,
        "record_count": len(rows),
        "counts": dict(sorted(counts.items())),
        "protected_change_count": len(protected_changes),
        "protected_changes": protected_changes,
        "ordinary_or_mutable_drift_is_parser_nondeterminism": False,
    }



def sha256_file(path: Path, max_bytes: int | None = None) -> str:
    raw = captured_bytes(path)
    if raw is not None:
        if max_bytes is not None and len(raw) > max_bytes:
            raise ValueError(f"hash_input_over_limit:{path}:{len(raw)}")
        return sha256_bytes(raw)
    size = path.stat().st_size
    if max_bytes is not None and size > max_bytes:
        raise ValueError(f"hash_input_over_limit:{path}:{size}")
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def read_text_bounded(path: Path, max_bytes: int) -> tuple[str, str, int]:
    raw = captured_bytes(path)
    if raw is None:
        size = path.stat().st_size
        if size > max_bytes:
            raise ValueError(f"file_over_limit:{path}:{size}")
        raw = path.read_bytes()
    if len(raw) > max_bytes:
        raise ValueError(f"file_over_limit:{path}:{len(raw)}")
    for encoding in ("utf-8-sig", "utf-8", "cp1252"):
        try:
            return raw.decode(encoding), encoding, len(raw)
        except UnicodeDecodeError:
            pass
    return raw.decode("utf-8", errors="replace"), "utf-8-replacement", len(raw)

def norm_win(value: str | Path | None) -> str:
    if value is None:
        return ""
    return str(value).replace("/", "\\").strip()


def redacted_text(text: str) -> str:
    return SECRET_LINE_RE.sub(lambda match: f"{match.group(1)}=[REDACTED]", text)


def strip_quotes(value: str) -> str:
    value = value.strip()
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {'"', "'"}:
        return value[1:-1]
    return value


def tokenize_windows(command: str) -> list[str]:
    return [strip_quotes(token) for token in TOKEN_RE.findall(command) if strip_quotes(token)]


def is_url(value: str) -> bool:
    return bool(re.match(r"(?i)^https?://", value.strip()))


def is_interpreter(value: str) -> bool:
    cleaned = strip_quotes(value).replace("/", "\\")
    if cleaned.casefold() in {"python", "python.exe", "pythonw", "pythonw.exe", "py", "py.exe"}:
        return True
    return bool(INTERPRETER_WORD_RE.search(cleaned))


def logical_lines(text: str, suffix: str) -> list[tuple[int, int, str]]:
    continuation = "`" if suffix.casefold() == ".ps1" else "^"
    result: list[tuple[int, int, str]] = []
    buffer: list[str] = []
    start = 0
    for line_no, raw in enumerate(text.splitlines(), start=1):
        line = raw.rstrip()
        if not buffer:
            start = line_no
        if line.endswith(continuation):
            buffer.append(line[:-1].rstrip())
            continue
        buffer.append(line)
        result.append((start, line_no, " ".join(part.strip() for part in buffer if part.strip())))
        buffer = []
    if buffer:
        result.append((start, len(text.splitlines()), " ".join(part.strip() for part in buffer if part.strip())))
    return result


def is_comment_or_blank(line: str, suffix: str, ps_block_comment: bool) -> tuple[bool, bool]:
    stripped = line.strip()
    if not stripped:
        return True, ps_block_comment
    if suffix.casefold() in {".bat", ".cmd"}:
        lowered = stripped.lstrip("@").casefold()
        return lowered.startswith("rem ") or lowered == "rem" or stripped.startswith("::"), ps_block_comment
    if suffix.casefold() == ".ps1":
        if ps_block_comment:
            return True, "#>" not in stripped
        if stripped.startswith("<#"):
            return True, "#>" not in stripped
        return stripped.startswith("#"), False
    return False, ps_block_comment


def expand_batch_value(value: str, variables: dict[str, str], launcher_dir: str) -> tuple[str, list[str]]:
    expanded = value.strip()
    expanded = DP0_RE.sub(lambda _match: launcher_dir.rstrip("\\") + "\\", expanded)
    unresolved: set[str] = set()
    for _ in range(12):
        changed = False
        for match in list(ENV_REF_RE.finditer(expanded)):
            token = match.group(0)
            key = token[1:-1].casefold()
            if key in variables:
                expanded = expanded[:match.start()] + variables[key] + expanded[match.end():]
                changed = True
                break
            if key == "comspec":
                continue
            unresolved.add(token)
        if not changed:
            break
    for match in ENV_REF_RE.finditer(expanded):
        token = match.group(0)
        if token[1:-1].casefold() != "comspec":
            unresolved.add(token)
    return expanded.strip(), sorted(unresolved, key=str.casefold)


def canonicalize_for_assignment(line: str, variables: dict[str, str], launcher_dir: str) -> dict[str, Any] | None:
    match = BATCH_FOR_CANON_RE.match(line)
    if not match:
        return None
    loop_var, raw_source, name = match.groups()
    expanded, unresolved = expand_batch_value(raw_source, variables, launcher_dir)
    canonical = ntpath.normpath(expanded)
    variables[name.casefold()] = canonical
    return {
        "name": name,
        "value": canonical,
        "raw_value": raw_source,
        "assignment_kind": "for_canonical_path",
        "loop_variable": loop_var,
        "unresolved_variables": unresolved,
    }


def project_relative_for_windows_path(candidate_text: str, project_root: Path) -> tuple[str | None, bool]:
    candidate = PureWindowsPath(candidate_text)
    root = PureWindowsPath(norm_win(project_root))
    try:
        relative = candidate.relative_to(root)
        return str(relative).replace("/", "\\"), True
    except ValueError:
        return None, False


def local_candidate_for_reference(candidate_text: str, launcher_path: Path, project_root: Path) -> tuple[Path | None, str | None, bool]:
    candidate_text = strip_quotes(candidate_text)
    if not candidate_text or is_url(candidate_text):
        return None, None, False
    pure = PureWindowsPath(candidate_text)
    if pure.is_absolute():
        relative, within = project_relative_for_windows_path(candidate_text, project_root)
        if within and relative is not None:
            return project_root / Path(relative), relative, True
        return Path(candidate_text), None, False
    local = launcher_path.parent / Path(candidate_text)
    try:
        relative = local.resolve(strict=False).relative_to(project_root.resolve(strict=False))
        return local, norm_win(relative), True
    except (ValueError, OSError):
        return local, None, False


def resolve_reference(raw_value: str, expanded_value: str, launcher_path: Path, project_root: Path, unresolved: list[str], reference_kind: str) -> dict[str, Any]:
    cleaned = strip_quotes(expanded_value.strip().rstrip("&|()"))
    base = {
        "reference_kind": reference_kind,
        "raw_value": raw_value,
        "expanded_value": cleaned,
        "unresolved_variables": sorted(set(unresolved), key=str.casefold),
        "confirmed_active_or_executed": False,
    }
    if not cleaned:
        return {**base, "classification": "empty_reference", "confirmation": "unresolved", "exists": False, "resolved_path": None, "relative_path": None, "within_project_root": False}
    if is_url(cleaned):
        return {**base, "classification": "url", "url": cleaned, "confirmation": "static_url_reference", "exists": False, "resolved_path": None, "relative_path": None, "within_project_root": False}
    if cleaned.casefold() in OS_SHELL_WORDS or raw_value.strip().casefold() == "%comspec%":
        return {**base, "classification": "operating_system_shell", "confirmation": "os_shell_reference", "exists": False, "resolved_path": None, "relative_path": None, "within_project_root": False}
    local, relative, within = local_candidate_for_reference(cleaned, launcher_path, project_root)
    exists = reference_exists_once(local)
    if unresolved:
        confirmation = "unresolved_reference"
    elif exists:
        confirmation = "static_existing_target"
    else:
        confirmation = "static_unverified_target"
    return {
        **base,
        "classification": "filesystem_reference",
        "confirmation": confirmation,
        "exists": exists,
        "resolved_path": norm_win(local) if local else None,
        "relative_path": relative,
        "within_project_root": within,
    }


def split_chain(command: str) -> list[str]:
    result: list[str] = []
    current: list[str] = []
    quote: str | None = None
    index = 0
    while index < len(command):
        char = command[index]
        if char in {'"', "'"}:
            if quote == char:
                quote = None
            elif quote is None:
                quote = char
            current.append(char)
            index += 1
            continue
        if quote is None and command[index:index + 2] in {"&&", "||"}:
            segment = "".join(current).strip()
            if segment:
                result.append(segment)
            current = []
            index += 2
            continue
        current.append(char)
        index += 1
    segment = "".join(current).strip()
    if segment:
        result.append(segment)
    return result


def find_script_token(tokens: list[str]) -> tuple[int | None, str | None]:
    for index, token in enumerate(tokens):
        cleaned = token.rstrip("&|()").strip("\'\"")
        suffix = PureWindowsPath(cleaned).suffix.casefold()
        if suffix in SCRIPT_SUFFIXES:
            return index, cleaned
    return None, None


def find_launcher_token(tokens: list[str]) -> tuple[int | None, str | None]:
    for index, token in enumerate(tokens):
        cleaned = token.rstrip("&|()").strip("\'\"")
        suffix = PureWindowsPath(cleaned).suffix.casefold()
        if suffix in LAUNCHER_SUFFIXES:
            return index, cleaned
    return None, None


def parse_command_segment(
    segment: str,
    *,
    line_no: int,
    launcher_path: Path,
    project_root: Path,
    variables: dict[str, str],
    record: dict[str, list[dict[str, Any]]],
    source_kind: str = "direct",
) -> None:
    raw_segment = segment.strip().lstrip("@").strip()
    if not raw_segment:
        return
    expanded, unresolved = expand_batch_value(raw_segment, variables, norm_win(launcher_path.parent))
    tokens = tokenize_windows(expanded)
    raw_tokens = tokenize_windows(raw_segment)
    if not tokens:
        return
    first = tokens[0].casefold().rstrip(":")
    if first in SHELL_BUILTINS and first not in {"call", "start"}:
        if first in FILE_OPERATION_WORDS:
            record["file_operations"].append({"line": line_no, "operation": first, "command": redacted_text(raw_segment[:1000])})
        else:
            record["control_flow"].append({"line": line_no, "kind": first, "command": redacted_text(raw_segment[:1000])})
        return

    if first == "call":
        if len(tokens) < 2:
            return
        target = tokens[1]
        if target.startswith(":"):
            record["control_flow"].append({"line": line_no, "kind": "call_label", "target_label": target[1:]})
            return
        raw_target = raw_tokens[1] if len(raw_tokens) > 1 else target
        reference = resolve_reference(raw_target, target, launcher_path, project_root, unresolved, "called_launcher")
        if PureWindowsPath(target).suffix.casefold() in LAUNCHER_SUFFIXES:
            record["called_launchers"].append({"line": line_no, "command": redacted_text(raw_segment[:1000]), **reference})
        else:
            record["unresolved_references"].append({"line": line_no, "reason": "call_target_not_launcher", **reference})
        return

    if first == "start":
        # Windows START treats its first quoted token as a window title. Parse it
        # from the raw command before tokenization so empty and named titles do
        # not become false executable targets.
        start_match = re.match(r'(?is)^start\s+(?:"[^"]*"\s+)?(.*)$', raw_segment)
        start_payload_raw = start_match.group(1).strip() if start_match else " ".join(raw_tokens[1:])
        start_payload_expanded, start_unresolved = expand_batch_value(start_payload_raw, variables, norm_win(launcher_path.parent))
        tokens = tokenize_windows(start_payload_expanded)
        raw_tokens = tokenize_windows(start_payload_raw)
        unresolved = sorted(set(unresolved) | set(start_unresolved), key=str.casefold)
        while tokens and tokens[0].casefold() in {"/b", "/d", "/i", "/min", "/max", "/wait", "/low", "/normal", "/high", "/realtime", "/abovenormal", "/belownormal"}:
            option = tokens.pop(0)
            if raw_tokens:
                raw_tokens.pop(0)
            if option.casefold() == "/d" and tokens:
                tokens.pop(0)
                if raw_tokens:
                    raw_tokens.pop(0)
        if not tokens:
            return
        target = tokens[0]
        raw_target = raw_tokens[0] if raw_tokens else target
        target_folded = target.casefold()
        if is_url(target):
            record["urls"].append({"line": line_no, "kind": "opened_url", "url": target, "command": redacted_text(raw_segment[:1000]), "confirmed_opened": False})
            return
        if target_folded in OS_SHELL_WORDS or raw_target.casefold() == "%comspec%":
            record["os_shell_references"].append({"line": line_no, "shell": target, "raw": raw_target, "confirmed_executed": False})
            nested = " ".join(tokens[1:])
            for chain_part in split_chain(nested):
                lowered = chain_part.casefold()
                call_match = re.search(r"""(?i)\bcall\s+("[^"]+\.(?:bat|cmd|ps1)"|\S+\.(?:bat|cmd|ps1))""", chain_part)
                if call_match:
                    parse_command_segment("call " + call_match.group(1), line_no=line_no, launcher_path=launcher_path, project_root=project_root, variables=variables, record=record, source_kind="nested_shell")
                python_match = re.search(r"""(?i)("[^"]*(?:python|pythonw)\.exe"|\bpythonw?\b|(?<![.\w])py(?:\.exe)?\b)\s+(.+)""", chain_part)
                if python_match:
                    parse_command_segment(python_match.group(0), line_no=line_no, launcher_path=launcher_path, project_root=project_root, variables=variables, record=record, source_kind="nested_shell")
            return
        remainder = [target] + tokens[1:]
        if is_interpreter(target):
            parse_interpreter_invocation(remainder, raw_tokens, line_no, raw_segment, launcher_path, project_root, variables, unresolved, record, source_kind)
            return
        suffix = PureWindowsPath(target).suffix.casefold()
        if suffix in LAUNCHER_SUFFIXES:
            reference = resolve_reference(raw_target, target, launcher_path, project_root, unresolved, "started_launcher")
            record["called_launchers"].append({"line": line_no, "command": redacted_text(raw_segment[:1000]), **reference})
            return
        reference = resolve_reference(raw_target, target, launcher_path, project_root, unresolved, "started_external_command")
        record["external_commands"].append({"line": line_no, "command": redacted_text(raw_segment[:1000]), **reference})
        return

    if first in OS_SHELL_WORDS:
        record["os_shell_references"].append({"line": line_no, "shell": tokens[0], "raw": raw_tokens[0] if raw_tokens else tokens[0], "confirmed_executed": False})
        nested = " ".join(tokens[1:])
        for chain_part in split_chain(nested):
            if re.search(r"(?i)\bcall\b", chain_part):
                call_match = re.search(r"""(?i)\bcall\s+("[^"]+\.(?:bat|cmd|ps1)"|\S+\.(?:bat|cmd|ps1))""", chain_part)
                if call_match:
                    parse_command_segment("call " + call_match.group(1), line_no=line_no, launcher_path=launcher_path, project_root=project_root, variables=variables, record=record, source_kind="nested_shell")
            python_match = re.search(r"""(?i)("[^"]*(?:python|pythonw)\.exe"|\bpythonw?\b|(?<![.\w])py(?:\.exe)?\b)\s+(.+)""", chain_part)
            if python_match:
                parse_command_segment(python_match.group(0), line_no=line_no, launcher_path=launcher_path, project_root=project_root, variables=variables, record=record, source_kind="nested_shell")
        return

    if is_interpreter(tokens[0]):
        parse_interpreter_invocation(tokens, raw_tokens, line_no, raw_segment, launcher_path, project_root, variables, unresolved, record, source_kind)
        return

    suffix = PureWindowsPath(tokens[0]).suffix.casefold()
    if suffix in LAUNCHER_SUFFIXES:
        reference = resolve_reference(raw_tokens[0] if raw_tokens else tokens[0], tokens[0], launcher_path, project_root, unresolved, "direct_launcher")
        record["called_launchers"].append({"line": line_no, "command": redacted_text(raw_segment[:1000]), **reference})
        return

    if suffix in {".exe", ".com"} or "\\" in tokens[0] or "/" in tokens[0]:
        reference = resolve_reference(raw_tokens[0] if raw_tokens else tokens[0], tokens[0], launcher_path, project_root, unresolved, "external_command")
        record["external_commands"].append({"line": line_no, "command": redacted_text(raw_segment[:1000]), **reference})


def parse_interpreter_invocation(
    tokens: list[str],
    raw_tokens: list[str],
    line_no: int,
    raw_segment: str,
    launcher_path: Path,
    project_root: Path,
    variables: dict[str, str],
    unresolved: list[str],
    record: dict[str, list[dict[str, Any]]],
    source_kind: str,
) -> None:
    interpreter = tokens[0]
    raw_interpreter = raw_tokens[0] if raw_tokens else interpreter
    interpreter_ref = resolve_reference(raw_interpreter, interpreter, launcher_path, project_root, unresolved, "python_interpreter")
    script_index, script = find_script_token(tokens[1:])
    script_ref: dict[str, Any] | None = None
    arguments: list[str]
    if script is not None and script_index is not None:
        true_index = script_index + 1
        raw_script = raw_tokens[true_index] if len(raw_tokens) > true_index else script
        raw_script = raw_script.strip("\'\"")
        script_expanded, script_unresolved = expand_batch_value(raw_script, variables, norm_win(launcher_path.parent))
        script_ref = resolve_reference(raw_script, script_expanded, launcher_path, project_root, script_unresolved, "python_script")
        arguments = tokens[true_index + 1:]
    else:
        arguments = tokens[1:]
    record["interpreter_invocations"].append({
        "line": line_no,
        "source_kind": source_kind,
        "command": redacted_text(raw_segment[:1000]),
        "interpreter": interpreter_ref,
        "script": script_ref,
        "arguments": [redacted_text(item[:300]) for item in arguments],
        "interpreter_executed": False,
        "script_executed": False,
    })


def parse_batch_launcher(path: Path, project_root: Path, classification: dict[str, Any]) -> dict[str, Any]:
    text, encoding, _ = read_text_bounded(path, MAX_LAUNCHER_FILE_BYTES)
    relative = norm_win(path.relative_to(project_root)) if path.is_relative_to(project_root) else norm_win(path.name)
    variables: dict[str, str] = {}
    fields: dict[str, list[dict[str, Any]]] = {
        "settings": [], "labels": [], "gotos": [], "working_directories": [], "existence_checks": [],
        "diagnostics": [], "file_operations": [], "control_flow": [], "called_launchers": [],
        "interpreter_invocations": [], "urls": [], "os_shell_references": [], "external_commands": [],
        "unresolved_references": [],
    }
    environment_references: set[str] = set()
    ports: set[int] = set()
    ps_block = False
    for line_no, end_line, logical in logical_lines(text, path.suffix):
        skip, ps_block = is_comment_or_blank(logical, path.suffix, ps_block)
        if skip:
            continue
        stripped = logical.strip()
        lowered = stripped.lstrip("@").casefold()
        for token in ENV_REF_RE.findall(stripped):
            environment_references.add(token)
        if DP0_RE.search(stripped):
            environment_references.add("%~dp0")
        expanded_line, _line_unresolved = expand_batch_value(stripped, variables, norm_win(path.parent))
        for url in URL_RE.findall(expanded_line):
            fields["urls"].append({"line": line_no, "kind": "static_url_reference", "url": url.rstrip(")],;"), "confirmed_opened": False})
        for port_text in PORT_RE.findall(expanded_line):
            port = int(port_text)
            if 1 <= port <= 65535:
                ports.add(port)
        label_match = BATCH_LABEL_RE.match(stripped)
        if label_match:
            fields["labels"].append({"name": label_match.group(1), "line": line_no})
            continue
        for_assignment = canonicalize_for_assignment(stripped, variables, norm_win(path.parent))
        if for_assignment:
            fields["settings"].append({"line": line_no, **for_assignment})
            continue
        set_match = BATCH_SET_RE.match(stripped)
        if set_match:
            name = (set_match.group(1) or set_match.group(3) or "").strip()
            raw_value = (set_match.group(2) if set_match.group(1) is not None else set_match.group(4) or "").strip()
            expanded, unresolved = expand_batch_value(raw_value, variables, norm_win(path.parent))
            variables[name.casefold()] = expanded
            fields["settings"].append({
                "name": name,
                "line": line_no,
                "value": "[REDACTED]" if SECRET_NAME_RE.search(name) else redacted_text(expanded[:800]),
                "raw_value": "[REDACTED]" if SECRET_NAME_RE.search(name) else redacted_text(raw_value[:800]),
                "assignment_kind": "set",
                "unresolved_variables": unresolved,
            })
            continue
        goto_match = BATCH_GOTO_RE.match(stripped)
        if goto_match:
            fields["gotos"].append({"target_label": goto_match.group(1), "line": line_no})
            fields["control_flow"].append({"line": line_no, "kind": "goto", "target": goto_match.group(1)})
            continue
        cd_match = BATCH_CD_RE.match(stripped)
        if cd_match:
            expanded, unresolved = expand_batch_value(cd_match.group(1), variables, norm_win(path.parent))
            reference = resolve_reference(cd_match.group(1), expanded, path, project_root, unresolved, "working_directory")
            fields["working_directories"].append({"line": line_no, **reference})
            continue
        exist_match = BATCH_EXIST_RE.match(stripped)
        if exist_match:
            negated = bool(exist_match.group(1))
            raw_test = exist_match.group(2).strip().rstrip("(").strip()
            expanded, unresolved = expand_batch_value(raw_test, variables, norm_win(path.parent))
            reference = resolve_reference(raw_test, expanded, path, project_root, unresolved, "existence_check")
            fields["existence_checks"].append({"line": line_no, "negated": negated, **reference})
            fields["control_flow"].append({"line": line_no, "kind": "if_not_exist" if negated else "if_exist"})
            continue
        if lowered.startswith("echo") or lowered.startswith("@echo"):
            fields["diagnostics"].append({"line": line_no, "kind": "echo", "text": redacted_text(stripped[:1000])})
            continue
        first_word = tokenize_windows(stripped.lstrip("@"))
        if first_word and first_word[0].casefold() in FILE_OPERATION_WORDS:
            fields["file_operations"].append({"line": line_no, "operation": first_word[0].casefold(), "command": redacted_text(stripped[:1000])})
            continue
        for segment in split_chain(stripped):
            parse_command_segment(segment, line_no=line_no, launcher_path=path, project_root=project_root, variables=variables, record=fields)

    def ordered(name: str, extra: tuple[str, ...] = ()) -> list[dict[str, Any]]:
        return sorted(fields[name], key=lambda item: (item.get("line", 0),) + tuple(str(item.get(key, "")).casefold() for key in extra))

    called = ordered("called_launchers", ("expanded_value",))
    return {
        "schema": BRIDGE_SCHEMA,
        "path": norm_win(path),
        "relative_path": relative,
        "suffix": path.suffix.casefold(),
        "size_bytes": path_size(path),
        "modified_ns": path_mtime_ns(path),
        "sha256": sha256_file(path, MAX_LAUNCHER_FILE_BYTES),
        "encoding": encoding,
        "line_count": len(text.splitlines()),
        "logical_line_count": len(logical_lines(text, path.suffix)),
        "parse_status": "refined_static_parsed",
        "path_classification": classification,
        "launcher_executed": False,
        "variables": {key: variables[key] for key in sorted(variables)},
        "settings": ordered("settings", ("name",)),
        "labels": ordered("labels", ("name",)),
        "gotos": ordered("gotos", ("target_label",)),
        "working_directories": ordered("working_directories"),
        "existence_checks": ordered("existence_checks"),
        "diagnostics": ordered("diagnostics"),
        "file_operations": ordered("file_operations", ("operation",)),
        "control_flow": ordered("control_flow", ("kind",)),
        "called_launchers": called,
        "edges": called,
        "interpreter_invocations": ordered("interpreter_invocations"),
        "urls": ordered("urls", ("url",)),
        "os_shell_references": ordered("os_shell_references", ("shell",)),
        "external_commands": ordered("external_commands", ("expanded_value",)),
        "unresolved_references": ordered("unresolved_references"),
        "ports": sorted(ports),
        "environment_references": sorted(environment_references, key=str.casefold),
        "confirmed_active_or_executed_targets": 0,
    }


def parse_powershell_launcher(path: Path, project_root: Path, classification: dict[str, Any]) -> dict[str, Any]:
    text, encoding, _ = read_text_bounded(path, MAX_LAUNCHER_FILE_BYTES)
    relative = norm_win(path.relative_to(project_root)) if path.is_relative_to(project_root) else norm_win(path.name)
    settings: list[dict[str, Any]] = []
    working: list[dict[str, Any]] = []
    called: list[dict[str, Any]] = []
    interpreters: list[dict[str, Any]] = []
    urls: list[dict[str, Any]] = []
    diagnostics: list[dict[str, Any]] = []
    external: list[dict[str, Any]] = []
    ports: set[int] = set()
    variables: dict[str, str] = {}
    in_block = False
    for line_no, _end, logical in logical_lines(text, path.suffix):
        skip, in_block = is_comment_or_blank(logical, path.suffix, in_block)
        if skip:
            continue
        stripped = logical.strip()
        if stripped.casefold().startswith(("write-host", "write-output", "write-warning", "write-error", "write-verbose")):
            diagnostics.append({"line": line_no, "kind": "powershell_output", "text": redacted_text(stripped[:1000])})
            continue
        assign = re.match(r"""(?i)^\s*(\$env:)?\$?([A-Za-z_][A-Za-z0-9_]*)\s*=\s*["']([^"']*)["']\s*$""", stripped)
        if assign:
            env_prefix, name, value = assign.groups()
            variables[name.casefold()] = value
            settings.append({"line": line_no, "name": ("env:" if env_prefix else "") + name, "value": "[REDACTED]" if SECRET_NAME_RE.search(name) else redacted_text(value), "assignment_kind": "powershell_assignment"})
            continue
        cd_match = re.match(r"""(?i)^\s*(?:set-location|cd|push-location)\s+(.+)$""", stripped)
        if cd_match:
            raw = cd_match.group(1)
            reference = resolve_reference(raw, strip_quotes(raw), path, project_root, [], "working_directory")
            working.append({"line": line_no, **reference})
            continue
        for url in URL_RE.findall(stripped):
            urls.append({"line": line_no, "kind": "static_url_reference", "url": url.rstrip(")],;"), "confirmed_opened": False})
        for port_text in PORT_RE.findall(stripped):
            port = int(port_text)
            if 1 <= port <= 65535:
                ports.add(port)
        start_match = re.match(r"""(?i)^\s*start-process\s+(?:-filepath\s+)?("[^"]+"|'[^']+'|\S+)(.*)$""", stripped)
        if start_match:
            target, remainder = strip_quotes(start_match.group(1)), start_match.group(2)
            if is_interpreter(target):
                fake_record = {"interpreter_invocations": interpreters}
                parse_interpreter_invocation([target] + tokenize_windows(remainder), [target] + tokenize_windows(remainder), line_no, stripped, path, project_root, variables, [], fake_record, "powershell_start_process")
            elif PureWindowsPath(target).suffix.casefold() in LAUNCHER_SUFFIXES:
                reference = resolve_reference(target, target, path, project_root, [], "powershell_started_launcher")
                called.append({"line": line_no, "command": redacted_text(stripped[:1000]), **reference})
            elif is_url(target):
                urls.append({"line": line_no, "kind": "opened_url", "url": target, "confirmed_opened": False})
            else:
                reference = resolve_reference(target, target, path, project_root, [], "powershell_external_command")
                external.append({"line": line_no, "command": redacted_text(stripped[:1000]), **reference})
            continue
        invoke_match = re.match(r"""^\s*&\s*("[^"]+"|'[^']+'|\S+)(.*)$""", stripped)
        if invoke_match:
            target, remainder = strip_quotes(invoke_match.group(1)), invoke_match.group(2)
            if is_interpreter(target):
                fake_record = {"interpreter_invocations": interpreters}
                parse_interpreter_invocation([target] + tokenize_windows(remainder), [target] + tokenize_windows(remainder), line_no, stripped, path, project_root, variables, [], fake_record, "powershell_call_operator")
            elif PureWindowsPath(target).suffix.casefold() in LAUNCHER_SUFFIXES:
                reference = resolve_reference(target, target, path, project_root, [], "powershell_invoked_launcher")
                called.append({"line": line_no, "command": redacted_text(stripped[:1000]), **reference})
            else:
                reference = resolve_reference(target, target, path, project_root, [], "powershell_external_command")
                external.append({"line": line_no, "command": redacted_text(stripped[:1000]), **reference})

    return {
        "schema": BRIDGE_SCHEMA,
        "path": norm_win(path),
        "relative_path": relative,
        "suffix": path.suffix.casefold(),
        "size_bytes": path_size(path),
        "modified_ns": path_mtime_ns(path),
        "sha256": sha256_file(path, MAX_LAUNCHER_FILE_BYTES),
        "encoding": encoding,
        "line_count": len(text.splitlines()),
        "parse_status": "refined_static_parsed",
        "path_classification": classification,
        "launcher_executed": False,
        "variables": {key: variables[key] for key in sorted(variables)},
        "settings": sorted(settings, key=lambda item: (item["line"], item["name"].casefold())),
        "labels": [], "gotos": [], "existence_checks": [], "file_operations": [], "control_flow": [],
        "working_directories": sorted(working, key=lambda item: item["line"]),
        "diagnostics": sorted(diagnostics, key=lambda item: item["line"]),
        "called_launchers": sorted(called, key=lambda item: item["line"]),
        "edges": sorted(called, key=lambda item: item["line"]),
        "interpreter_invocations": sorted(interpreters, key=lambda item: item["line"]),
        "urls": sorted(urls, key=lambda item: (item["line"], item["url"].casefold())),
        "os_shell_references": [],
        "external_commands": sorted(external, key=lambda item: item["line"]),
        "unresolved_references": [],
        "ports": sorted(ports),
        "environment_references": [],
        "confirmed_active_or_executed_targets": 0,
    }


def parse_launcher(path: Path, project_root: Path, classification: dict[str, Any]) -> dict[str, Any]:
    if path.suffix.casefold() == ".ps1":
        return parse_powershell_launcher(path, project_root, classification)
    return parse_batch_launcher(path, project_root, classification)


def load_json(path: Path) -> Any:
    return json.loads(path.read_text(encoding="utf-8"))



def read_verified_file_once(path: Path, expected_size: int | None = None, expected_sha256: str | None = None) -> tuple[bytes, dict[str, Any]]:
    if not path.is_file() or path.is_symlink():
        raise FileNotFoundError(path)
    raw = path.read_bytes()
    actual_sha = sha256_bytes(raw)
    if expected_size is not None and len(raw) != expected_size:
        raise ValueError(f"prerequisite_size_mismatch:{path}")
    if expected_sha256 is not None and actual_sha != expected_sha256:
        raise ValueError(f"prerequisite_hash_mismatch:{path}")
    try:
        modified_ns = path.stat().st_mtime_ns
    except OSError:
        modified_ns = 0
    return raw, {
        "path": norm_win(path), "_native_path": str(path), "relative_path": None, "roles": ["v1a2_prerequisite"],
        "protected": True, "prerequisite": True, "payload": False,
        "expected_sha256": expected_sha256, "capture_max_bytes": max(len(raw), 1),
        "is_symlink": False, "status": "captured", "size_bytes": len(raw),
        "modified_ns": modified_ns, "sha256": actual_sha, "changed_during_capture": False,
        "_bytes": raw,
    }


def load_verified_v1a2_bundle(v1a2_dir: Path) -> dict[str, Any]:
    receipt_path = v1a2_dir / "STATIC_BRIDGE_RECEIPT.json"
    receipt_raw, receipt_capture = read_verified_file_once(receipt_path)
    receipt = json.loads(receipt_raw.decode("utf-8"))
    if receipt.get("result") != "static_code_and_launcher_bridge_complete":
        raise ValueError("v1a2_source_not_complete")
    captures = {capture_key(receipt_path): receipt_capture}
    objects: dict[str, Any] = {"STATIC_BRIDGE_RECEIPT.json": receipt}
    checked: list[dict[str, Any]] = []
    for item in receipt.get("core_outputs_before_receipt", []):
        path = v1a2_dir / item["name"]
        raw, record = read_verified_file_once(path, int(item["size_bytes"]), str(item["sha256"]))
        record["capture_max_bytes"] = max(len(raw), 1)
        captures[capture_key(path)] = record
        checked.append({"name": item["name"], "size_bytes": len(raw), "sha256": sha256_bytes(raw)})
        if path.suffix.casefold() == ".json":
            objects[item["name"]] = json.loads(raw.decode("utf-8"))
    required = {"STATIC_CODE_INDEX.json", "STATIC_LAUNCHER_INDEX.json", "STATIC_REFERENCE_INDEX.json", "KNOWN_GOOD_COMPARISON.json"}
    missing = sorted(required - set(objects))
    if missing:
        raise ValueError(f"v1a2_required_outputs_missing:{missing}")
    return {"receipt": receipt, "objects": objects, "captures": captures, "verified_files": checked}


def capture_authorized_inputs(project_root: Path, bundle: dict[str, Any]) -> dict[str, dict[str, Any]]:
    global _ACTIVE_CAPTURE
    _ACTIVE_CAPTURE = dict(bundle["captures"])
    prior_code = bundle["objects"]["STATIC_CODE_INDEX.json"]
    prior_launcher = bundle["objects"]["STATIC_LAUNCHER_INDEX.json"]
    known_good = bundle["objects"]["KNOWN_GOOD_COMPARISON.json"]
    capture_requests: dict[str, dict[str, Any]] = {}

    def request(path: Path, role: str, relative: str | None, max_bytes: int, expected: str | None = None, protected: bool = False) -> None:
        key = capture_key(path)
        row = capture_requests.setdefault(key, {"path": path, "roles": [], "relative": relative, "max_bytes": 0, "expected": expected, "protected": False})
        row["roles"].append(role)
        row["max_bytes"] = max(row["max_bytes"], max_bytes)
        row["protected"] = bool(row["protected"] or protected)
        if expected and not row.get("expected"):
            row["expected"] = expected

    for item in prior_code.get("files", []):
        relative = str(item.get("relative_path", ""))
        request(project_root / Path(relative), "v1a2_source_record", relative, MAX_SOURCE_FILE_BYTES,
                item.get("source_bytes_sha256") or item.get("sha256"), False)
    for item in prior_launcher.get("records", []):
        raw = item.get("path")
        path = Path(raw) if raw else project_root / Path(str(item.get("relative_path", "")))
        request(path, "v1a2_launcher_record", str(item.get("relative_path", "")), MAX_LAUNCHER_FILE_BYTES, item.get("sha256"), False)
    for item in known_good.get("records", []):
        relative = str(item.get("path") or item.get("relative_path") or "")
        if relative:
            path = project_root / Path(relative)
            request(path, "known_good_protected_candidate", relative, MAX_SOURCE_FILE_BYTES,
                    item.get("expected_sha256") or item.get("sha256"), True)
    technical_core = project_root / "System" / "AgentFoxTechnicalCore"
    optional_protected = [
        technical_core / "EVIDENCE_CONTRACT_V1.json",
        technical_core / "static_code_launcher_bridge_v1.py",
        technical_core / "STATIC_CODE_LAUNCHER_CONTRACT_V1.json",
        Path(__file__),
        technical_core / "STATIC_CODE_LAUNCHER_CONTRACT_V1R2.json",
        technical_core / "README_V1A2R2.md",
    ]
    for path in optional_protected:
        request(path, "technical_core_contract_or_payload", None, 32 * 1024 * 1024, None, True)
    for key in sorted(capture_requests):
        row = capture_requests[key]
        captured = capture_one(row["path"], roles=row["roles"], relative_path=row["relative"], max_bytes=row["max_bytes"],
                    expected_sha256=row.get("expected"), protected=row["protected"], payload="payload" in " ".join(row["roles"]))
        if captured.get("protected") and captured.get("changed_during_capture"):
            raise ValueError(f"protected_input_changed_during_capture:{captured.get('path')}")
        if captured.get("protected") and captured.get("expected_sha256") and captured.get("status") == "captured" and captured.get("sha256") != captured.get("expected_sha256"):
            raise ValueError(f"protected_input_hash_mismatch:{captured.get('path')}")
    return _ACTIVE_CAPTURE


def build_bridge_from_capture(project_root: Path, mission_id: str, bundle: dict[str, Any]) -> tuple[dict[str, Any], dict[str, bytes]]:
    source_receipt = bundle["receipt"]
    prior_code = bundle["objects"]["STATIC_CODE_INDEX.json"]
    prior_launcher = bundle["objects"]["STATIC_LAUNCHER_INDEX.json"]
    prior_reference = bundle["objects"]["STATIC_REFERENCE_INDEX.json"]
    known_good = bundle["objects"]["KNOWN_GOOD_COMPARISON.json"]

    code_files = sorted(prior_code.get("files", []), key=lambda item: str(item.get("relative_path", "")).casefold())
    line_records: list[dict[str, Any]] = []
    reference_coverage: list[dict[str, Any]] = []
    current_hashes: list[dict[str, Any]] = []
    for file_record in code_files:
        relative = str(file_record.get("relative_path", ""))
        path = project_root / Path(relative)
        current_hashes.append(current_hash_status(file_record, project_root))
        records, coverage = collect_reference_lines(path, relative, str(file_record.get("language", "text")))
        line_records.extend(records)
        reference_coverage.append(coverage)

    shard_files, shard_catalog = create_reference_shards(line_records)
    launcher_records: list[dict[str, Any]] = []
    launcher_errors = Counter()
    for prior in sorted(prior_launcher.get("records", []), key=lambda item: str(item.get("relative_path", "")).casefold()):
        raw_path = prior.get("path")
        path = Path(raw_path) if raw_path else project_root / Path(prior.get("relative_path", ""))
        classification = prior.get("path_classification", {})
        if not path_is_file(path) or path_is_symlink(path):
            launcher_records.append({
                "schema": BRIDGE_SCHEMA, "path": norm_win(path), "relative_path": prior.get("relative_path"),
                "path_classification": classification, "parse_status": "missing_or_unreadable", "launcher_executed": False,
                "settings": [], "labels": [], "gotos": [], "working_directories": [], "existence_checks": [],
                "diagnostics": [], "file_operations": [], "control_flow": [], "called_launchers": [], "edges": [],
                "interpreter_invocations": [], "urls": [], "os_shell_references": [], "external_commands": [],
                "unresolved_references": [], "ports": [], "environment_references": [],
                "confirmed_active_or_executed_targets": 0,
            })
            launcher_errors["missing_or_unreadable"] += 1
            continue
        try:
            launcher_records.append(parse_launcher(path, project_root, classification))
        except (PermissionError, OSError, ValueError) as exc:
            launcher_records.append({
                "schema": BRIDGE_SCHEMA, "path": norm_win(path), "relative_path": prior.get("relative_path"),
                "path_classification": classification, "parse_status": "read_error", "error": f"{type(exc).__name__}:{exc}",
                "launcher_executed": False, "settings": [], "labels": [], "gotos": [], "working_directories": [],
                "existence_checks": [], "diagnostics": [], "file_operations": [], "control_flow": [],
                "called_launchers": [], "edges": [], "interpreter_invocations": [], "urls": [],
                "os_shell_references": [], "external_commands": [], "unresolved_references": [], "ports": [],
                "environment_references": [], "confirmed_active_or_executed_targets": 0,
            })
            launcher_errors["read_error"] += 1

    metrics = launcher_false_edge_metrics(launcher_records)
    launcher_index = {
        "schema": BRIDGE_SCHEMA, "mission_id": mission_id, "project_root": norm_win(project_root),
        "static_only": True, "immutable_input_capture_used": True, "launchers_executed": False,
