        "record_count": len(launcher_records),
        "edge_count": sum(len(item.get("edges", [])) for item in launcher_records),
        "interpreter_invocation_count": sum(len(item.get("interpreter_invocations", [])) for item in launcher_records),
        "url_reference_count": sum(len(item.get("urls", [])) for item in launcher_records),
