        "global_line_record_ceiling_used": False, "per_file_line_limit": MAX_REFERENCE_LINES_PER_FILE,
        "line_record_count": len(line_records), "source_file_coverage_count": len(reference_coverage),
        "source_file_coverage": reference_coverage, "shard_count": len(shard_catalog), "shards": shard_catalog,
        "symbol_index": prior_reference.get("symbol_index", {}), "import_index": prior_reference.get("import_index", {}),
        "setting_index": prior_reference.get("setting_index", {}), "reference_index": prior_reference.get("reference_index", {}),
