def build_immutable_bridge(project_root: Path, v1a2_dir: Path, mission_id: str) -> dict[str, bytes]:
    bundle = load_verified_v1a2_bundle(v1a2_dir)
    captures = capture_authorized_inputs(project_root, bundle)
    set_active_capture(captures)
    outputs_a, shards_a = build_bridge_from_capture(project_root, mission_id, bundle)
    serialized_a = finalize_outputs(outputs_a, shards_a)
    outputs_b, shards_b = build_bridge_from_capture(project_root, mission_id, bundle)
    serialized_b = finalize_outputs(outputs_b, shards_b)
    names_a, names_b = set(serialized_a), set(serialized_b)
    mismatches = sorted(name for name in names_a & names_b if serialized_a[name] != serialized_b[name])
    if names_a != names_b or mismatches:
        raise ValueError(f"immutable_input_determinism_failed:missing_a={sorted(names_b-names_a)}:missing_b={sorted(names_a-names_b)}:mismatches={mismatches}")
    determinism = {
        "schema": BRIDGE_SCHEMA,
        "comparison_kind": "two_internal_builds_from_one_immutable_capture",
        "byte_for_byte_match": True,
        "compared_output_count": len(serialized_a),
        "compared_outputs": [
            {"name": name, "size_bytes": len(serialized_a[name]), "sha256": sha256_bytes(serialized_a[name])}
            for name in sorted(serialized_a)
        ],
        "live_tree_reread_for_second_build": False,
    }
    drift = live_drift_report(captures)
    if drift["protected_change_count"]:
        raise ValueError(f"protected_or_prerequisite_drift_detected:{drift['protected_changes']}")
    manifest_records = [public_capture_record(captures[key]) for key in sorted(captures)]
    capture_manifest = {
        "schema": BRIDGE_SCHEMA,
        "capture_kind": "single_read_immutable_in_memory",
        "record_count": len(manifest_records),
        "records": manifest_records,
        "capture_status": dict(sorted(Counter(item.get("status", "unknown") for item in manifest_records).items())),
        "reference_existence_checks": [_REFERENCE_EXISTENCE_CACHE[key] for key in sorted(_REFERENCE_EXISTENCE_CACHE)],
        "reference_existence_check_count": len(_REFERENCE_EXISTENCE_CACHE),
        "raw_source_content_persisted": False,
    }
    outputs_a["INPUT_CAPTURE_MANIFEST.json"] = capture_manifest
    outputs_a["IMMUTABLE_DETERMINISM_REPORT.json"] = determinism
    outputs_a["LIVE_DRIFT_REPORT.json"] = drift
    outputs_a["REFINED_INDEX_COVERAGE.json"]["live_drift_summary"] = drift["counts"]
    outputs_a["REFINED_BRIDGE_RECEIPT.json"].update({
        "immutable_internal_double_build_match": True,
        "live_tree_reread_for_second_build": False,
        "input_capture_record_count": len(manifest_records),
        "reference_existence_check_count": len(_REFERENCE_EXISTENCE_CACHE),
        "live_drift_counts": drift["counts"],
        "protected_change_count": drift["protected_change_count"],
    })
    return finalize_outputs(outputs_a, shards_a)

def collect_reference_lines(path: Path, relative_path: str, language: str) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not path_is_file(path) or path_is_symlink(path):
        return [], {"path": relative_path, "status": "missing_or_unreadable", "total_lines": None, "indexed_lines": 0, "omitted_lines": None}
    if path_size(path) > MAX_SOURCE_FILE_BYTES:
        return [], {"path": relative_path, "status": "file_over_limit", "total_lines": None, "indexed_lines": 0, "omitted_lines": None, "size_bytes": path_size(path)}
    try:
        text, encoding, byte_count = read_text_bounded(path, MAX_SOURCE_FILE_BYTES)
    except (PermissionError, OSError, ValueError) as exc:
        return [], {"path": relative_path, "status": "read_error", "error": f"{type(exc).__name__}:{exc}", "total_lines": None, "indexed_lines": 0, "omitted_lines": None}
    records: list[dict[str, Any]] = []
    total_nonblank = 0
    ps_block = False
    for line_no, raw in enumerate(text.splitlines(), start=1):
        stripped = raw.strip()
        if not stripped:
            continue
        skip, ps_block = is_comment_or_blank(stripped, Path(relative_path).suffix, ps_block)
        if skip:
            continue
        total_nonblank += 1
        if len(records) < MAX_REFERENCE_LINES_PER_FILE:
            records.append({
                "path": relative_path,
                "line": line_no,
                "language": language,
                "text": redacted_text(stripped[:MAX_LINE_LENGTH]),
            })
    return records, {
        "path": relative_path,
        "status": "complete" if total_nonblank <= MAX_REFERENCE_LINES_PER_FILE else "per_file_line_limit_reached",
        "encoding": encoding,
        "source_bytes_read": byte_count,
        "total_nonblank_noncomment_lines": total_nonblank,
        "indexed_lines": len(records),
        "omitted_lines": max(0, total_nonblank - len(records)),
        "per_file_line_limit": MAX_REFERENCE_LINES_PER_FILE,
    }

def create_reference_shards(line_records: list[dict[str, Any]]) -> tuple[dict[str, bytes], list[dict[str, Any]]]:
    shards: dict[str, bytes] = {}
    catalog: list[dict[str, Any]] = []
    current: list[dict[str, Any]] = []
    current_estimate = 0
    shard_number = 1

    def flush() -> None:
        nonlocal current, current_estimate, shard_number
        if not current:
            return
        name = f"reference_shards/REFERENCE_LINES_{shard_number:04d}.json"
        value = {"schema": BRIDGE_SCHEMA, "shard_number": shard_number, "records": current, "record_count": len(current)}
        data = pretty_bytes(value)
        shards[name] = data
        catalog.append({
            "name": name,
            "record_count": len(current),
            "size_bytes": len(data),
            "sha256": sha256_bytes(data),
            "first_path": current[0]["path"],
            "last_path": current[-1]["path"],
        })
        shard_number += 1
        current = []
        current_estimate = 0

    for record in sorted(line_records, key=lambda item: (item["path"].casefold(), item["line"])):
        estimate = len(pretty_bytes(record)) + 16
        if current and (len(current) >= MAX_REFERENCE_SHARD_RECORDS or current_estimate + estimate > MAX_REFERENCE_SHARD_BYTES):
            flush()
        current.append(record)
        current_estimate += estimate
    flush()
    return shards, catalog



def current_hash_status(file_record: dict[str, Any], project_root: Path) -> dict[str, Any]:
    relative = file_record.get("relative_path", "")
    path = project_root / Path(relative)
    expected = file_record.get("source_bytes_sha256") or file_record.get("sha256")
    if not path_is_file(path) or path_is_symlink(path):
        return {"path": relative, "status": "missing", "expected_sha256": expected, "actual_sha256": None}
    if path_size(path) > MAX_SOURCE_FILE_BYTES:
        return {"path": relative, "status": "over_limit", "expected_sha256": expected, "actual_sha256": None, "size_bytes": path_size(path)}
    actual = sha256_file(path, MAX_SOURCE_FILE_BYTES)
    return {"path": relative, "status": "match" if expected == actual else "changed_since_v1a2", "expected_sha256": expected, "actual_sha256": actual, "size_bytes": path_size(path)}

def launcher_false_edge_metrics(records: list[dict[str, Any]]) -> dict[str, Any]:
    builtins: list[dict[str, Any]] = []
    url_paths: list[dict[str, Any]] = []
    comments: list[dict[str, Any]] = []
    unresolved_confirmed: list[dict[str, Any]] = []
    for record in records:
        for edge in record.get("edges", []):
            expanded = str(edge.get("expanded_value", ""))
            first = expanded.split(maxsplit=1)[0].casefold() if expanded else ""
            if first in SHELL_BUILTINS:
                builtins.append({"launcher": record.get("relative_path"), "edge": edge})
            if is_url(expanded) and edge.get("classification") == "filesystem_reference":
                url_paths.append({"launcher": record.get("relative_path"), "edge": edge})
            command = str(edge.get("command", "")).strip()
            if command.startswith(("#", "::")) or command.casefold().startswith("rem "):
                comments.append({"launcher": record.get("relative_path"), "edge": edge})
            if edge.get("unresolved_variables") and edge.get("confirmation") == "static_existing_target":
                unresolved_confirmed.append({"launcher": record.get("relative_path"), "edge": edge})
    return {
        "shell_builtin_launch_edge_count": len(builtins),
        "url_as_filesystem_edge_count": len(url_paths),
        "comment_launch_edge_count": len(comments),
        "unresolved_confirmed_target_count": len(unresolved_confirmed),
        "samples": {
            "shell_builtins": builtins[:10], "url_paths": url_paths[:10],
            "comments": comments[:10], "unresolved_confirmed": unresolved_confirmed[:10],
        },
    }



def build_bridge(project_root: Path, v1a2_dir: Path, mission_id: str) -> dict[str, bytes]:
    return build_immutable_bridge(project_root, v1a2_dir, mission_id)

