def finalize_outputs(outputs: dict[str, Any], shard_files: dict[str, bytes]) -> dict[str, bytes]:
    serialized = {name: pretty_bytes(value) for name, value in outputs.items()}
    serialized.update(shard_files)
    serialized["QUERY_EXAMPLES.md"] = query_examples_text().encode("utf-8")
    receipt = dict(outputs["REFINED_BRIDGE_RECEIPT.json"])
    receipt["core_outputs_before_receipt"] = [
        {"name": name, "size_bytes": len(data), "sha256": sha256_bytes(data)}
        for name, data in sorted(serialized.items())
        if name != "REFINED_BRIDGE_RECEIPT.json"
    ]
    serialized["REFINED_BRIDGE_RECEIPT.json"] = pretty_bytes(receipt)
    total = sum(len(data) for data in serialized.values())
    if total > MAX_OUTPUT_BYTES:
        raise ValueError(f"output_ceiling_exceeded:{total}")
    return serialized


def write_outputs(output_dir: Path, serialized: dict[str, bytes], verify_existing: bool = False) -> None:
    if verify_existing:
        missing: list[str] = []
        mismatches: list[str] = []
        for name, data in serialized.items():
            path = output_dir / Path(name)
            if not path.is_file():
                missing.append(name)
            elif path.read_bytes() != data:
                mismatches.append(name)
        if missing or mismatches:
            raise ValueError(f"determinism_check_failed:missing={missing}:mismatches={mismatches}")
        print("AGENT_FOX_V1A2R2_DETERMINISM_VERIFIED")
        return
    output_dir.mkdir(parents=True, exist_ok=True)
    expected = {Path(name) for name in serialized}
    existing = {path.relative_to(output_dir) for path in output_dir.rglob("*") if path.is_file()}
    unexpected = sorted(norm_win(path) for path in existing - expected)
    if unexpected:
        raise ValueError(f"unexpected_existing_output_files:{unexpected}")
    for name, data in serialized.items():
        path = output_dir / Path(name)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_bytes(data)



def load_indexes(index_dir: Path) -> dict[str, Any]:
    required = [
        "STATIC_CODE_INDEX.json", "REFINED_STATIC_LAUNCHER_INDEX.json", "STATIC_REFERENCE_CATALOG.json",
        "KNOWN_GOOD_COMPARISON.json", "REFINED_INDEX_COVERAGE.json", "INPUT_CAPTURE_MANIFEST.json",
        "IMMUTABLE_DETERMINISM_REPORT.json", "LIVE_DRIFT_REPORT.json", "REFINED_BRIDGE_RECEIPT.json",
    ]
    return {name: load_json(index_dir / name) for name in required}

def find_path_record(records: Iterable[dict[str, Any]], path_text: str) -> list[dict[str, Any]]:
    wanted = norm_win(path_text).casefold().lstrip("\\")
    exact: list[dict[str, Any]] = []
    suffix: list[dict[str, Any]] = []
    for record in records:
        relative = norm_win(record.get("relative_path", "")).casefold().lstrip("\\")
        full = norm_win(record.get("path", "")).casefold()
        if wanted in {relative, full}:
            exact.append(record)
        elif relative.endswith(wanted) or full.endswith(wanted):
            suffix.append(record)
    return exact or suffix


def trace_launcher(records: list[dict[str, Any]], start_path: str, max_depth: int = MAX_TRACE_DEPTH) -> dict[str, Any]:
    by_relative = {norm_win(item.get("relative_path", "")).casefold(): item for item in records}
    matches = find_path_record(records, start_path)
    if not matches:
        return {"finding": "launcher_not_found", "path": start_path, "trace": []}
    queue: deque[tuple[dict[str, Any], int]] = deque([(matches[0], 0)])
    visited: set[str] = set()
    trace: list[dict[str, Any]] = []
    while queue:
        current, depth = queue.popleft()
        key = norm_win(current.get("relative_path", "")).casefold()
        if key in visited or depth > max_depth:
            continue
        visited.add(key)
        trace.append({
            "depth": depth,
            "path": current.get("relative_path"),
            "parse_status": current.get("parse_status"),
            "variables": current.get("variables", {}),
            "working_directories": current.get("working_directories", []),
            "ports": current.get("ports", []),
            "urls": current.get("urls", []),
            "interpreter_invocations": current.get("interpreter_invocations", []),
            "called_launchers": current.get("called_launchers", []),
            "os_shell_references": current.get("os_shell_references", []),
            "existence_checks": current.get("existence_checks", []),
        })
        for edge in current.get("called_launchers", []):
            relative = norm_win(edge.get("relative_path", "")).casefold()
            if relative in by_relative and relative not in visited:
                queue.append((by_relative[relative], depth + 1))
    return {
        "finding": "refined_static_launcher_trace",
        "starting_path": matches[0].get("relative_path"),
        "execution_performed": False,
        "static_reference_is_not_runtime_proof": True,
        "trace": trace,
    }


def search_shards(index_dir: Path, catalog: dict[str, Any], term: str, limit: int) -> tuple[list[dict[str, Any]], int]:
    needle = term.casefold()
    results: list[dict[str, Any]] = []
    total = 0
    for shard in catalog.get("shards", []):
        data = load_json(index_dir / Path(shard["name"]))
        for item in data.get("records", []):
            if needle in item.get("text", "").casefold():
                total += 1
                if len(results) < limit:
                    results.append(item)
    return results, total


def run_query(index_dir: Path, mode: str, term: str | None, path_text: str | None, limit: int) -> dict[str, Any]:
    indexes = load_indexes(index_dir)
    code = indexes["STATIC_CODE_INDEX.json"]
    launchers = indexes["REFINED_STATIC_LAUNCHER_INDEX.json"]
    references = indexes["STATIC_REFERENCE_CATALOG.json"]
    limit = max(1, min(limit, MAX_QUERY_RESULTS))
    if mode == "search":
        if not term:
            raise ValueError("search_requires_term")
        results, total = search_shards(index_dir, references, term, limit)
        return {"finding": "sharded_static_text_matches", "term": term, "match_count": total, "results": results, "truncated": total > limit}
    if mode == "explain":
        if not path_text:
            raise ValueError("explain_requires_path")
        return {
            "finding": "file_static_explanation", "path": path_text,
            "code_records": find_path_record(code.get("files", []), path_text)[:limit],
            "launcher_records": find_path_record(launchers.get("records", []), path_text)[:limit],
            "execution_performed": False,
        }
    if mode == "trace-launcher":
        if not path_text:
            raise ValueError("trace_launcher_requires_path")
        return trace_launcher(launchers.get("records", []), path_text)
    if mode in {"find-symbol", "find-setting", "find-references"}:
        if not term:
            raise ValueError(f"{mode}_requires_term")
        table_name = {"find-symbol": "symbol_index", "find-setting": "setting_index", "find-references": "reference_index"}[mode]
        table = references.get(table_name, {})
        needle = term.casefold()
        found = list(table.get(needle, []))
        if not found:
            for key in sorted(table):
                if needle in key:
                    found.extend(table[key])
                    if len(found) >= limit:
                        break
        return {"finding": mode.replace("find-", "") + "_matches", "term": term, "results": found[:limit], "truncated": len(found) > limit}
    if mode == "compare-known-good":
        return indexes["KNOWN_GOOD_COMPARISON.json"]
    raise ValueError(f"unsupported_query_mode:{mode}")


def validate_known_launcher_record(record: dict[str, Any], expected: dict[str, Any]) -> None:
    assert record.get("parse_status") == "refined_static_parsed"
    variables = {key.casefold(): value for key, value in record.get("variables", {}).items()}
    for key, suffix in expected.get("variables", {}).items():
        assert key.casefold() in variables, f"missing variable {key} in {record.get('relative_path')}"
        assert norm_win(variables[key.casefold()]).casefold().endswith(norm_win(suffix).casefold()), (key, variables[key.casefold()], suffix)
    interpreter_paths = [norm_win(item.get("interpreter", {}).get("expanded_value", "")).casefold() for item in record.get("interpreter_invocations", [])]
    script_paths = [norm_win((item.get("script") or {}).get("expanded_value", "")).casefold() for item in record.get("interpreter_invocations", []) if item.get("script")]
    launcher_paths = [norm_win(item.get("expanded_value", "")).casefold() for item in record.get("called_launchers", [])]
    urls = [item.get("url", "").casefold() for item in record.get("urls", [])]
    for suffix in expected.get("interpreters", []):
        assert any(value.endswith(norm_win(suffix).casefold()) for value in interpreter_paths), (record.get("relative_path"), "interpreter", suffix, interpreter_paths)
    for suffix in expected.get("scripts", []):
        assert any(value.endswith(norm_win(suffix).casefold()) for value in script_paths), (record.get("relative_path"), "script", suffix, script_paths)
    for suffix in expected.get("launchers", []):
        assert any(value.endswith(norm_win(suffix).casefold()) for value in launcher_paths), (record.get("relative_path"), "launcher", suffix, launcher_paths)
    for url in expected.get("urls", []):
        assert url.casefold() in urls, (record.get("relative_path"), "url", url, urls)
    for port in expected.get("ports", []):
        assert port in record.get("ports", []), (record.get("relative_path"), "port", port, record.get("ports"))



def self_test() -> None:
    variables: dict[str, str] = {}
    for_line = r'FOR %%I IN ("%~dp0.") DO SET "FOXAI_ROOT=%%~fI"'
    result = canonicalize_for_assignment(for_line, variables, r"Z:\FOXAI")
    assert result is not None and variables["foxai_root"] == r"Z:\FOXAI"
    variables["python"] = r"%FOXAI_ROOT%\Runtime\Desktop\python\python.exe"
    expanded, unresolved = expand_batch_value(r"%PYTHON%", variables, r"Z:\FOXAI")
    assert expanded == r"Z:\FOXAI\Runtime\Desktop\python\python.exe" and unresolved == []
    assert expand_batch_value(r"%UNKNOWN%\x.py", variables, r"Z:\FOXAI")[1] == ["%UNKNOWN%"]
    assert is_url("http://127.0.0.1:8765") and not is_url(r"Z:\FOXAI\http")
    assert redacted_text("token=abc") == "token=[REDACTED]"

    root = Path("/virtual/FOXAI")
    samples = {
        "START_FOXAI_WEB_WITH_COMFYUI.bat": r'''@echo off
